        Header[标题：紧急会议/尸体发现]
        Timer[倒计时]
        DeadList[尸体列表]
        PlayerGrid[玩家头像网格]
        VoteSection[投票选择区域]
        SkipButton[跳过/弃权]
        ConfirmButton[确认投票]
    end
    
    PlayerGrid --> VoteSection
    VoteSection --> ConfirmButton
